+/**
+ * Clones a schema value and replaces recur placeholders.
+ *
+ * @param value The schema value.
+ * @param replacement The replacement schema.
+ * @param cache The clone cache.
+ *
+ * @returns The cloned value.
+ *
+ * @internal
+ */
+function _resolveRecur(
+  value: unknown,
+  replacement: BaseSchema<unknown, unknown, BaseIssue<unknown>> | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
+  cache: WeakMap<object, unknown>
+): unknown {
+  if (value === Recur) {
+    return replacement;
+  }
+  if (!value || typeof value !== 'object') {
+    return value;
+  }
+  const cached = cache.get(value);
+  if (cached) {
+    return cached;
+  }
+  if (Array.isArray(value)) {
+    const clone: unknown[] = [];
+    cache.set(value, clone);
+    for (const item of value) {
+      clone.push(_resolveRecur(item, replacement, cache));
+    }
+    return clone;
+  }
+  if (Object.getPrototypeOf(value) !== Object.prototype) {
+    return value;
+  }
+  const clone = Object.create(Object.getPrototypeOf(value)) as Record<
+    PropertyKey,
+    unknown
+  >;
+  cache.set(value, clone);
+  for (const key of Reflect.ownKeys(value)) {
+    const descriptor = Object.getOwnPropertyDescriptor(value, key)!;
+    Object.defineProperty(
+      clone,
+      key,
+      'value' in descriptor
+        ? {
+            ...descriptor,
+            value: _resolveRecur(descriptor.value, replacement, cache),
+          }
+        : descriptor
+    );
+  }
+  return clone;
+}
